import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';
import toast from 'react-hot-toast';

const ForgotPasswordPage = () => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [resetLink, setResetLink] = useState('');
  const [showLink, setShowLink] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await api.post('/auth/forgot-password', { email });
      console.log('Forgot password response:', response);
      
      if (response.data.success) {
        toast.success('Password reset link sent to your email');
        // If backend returned token (development), show it instead of redirect
        if (response.data.token) {
          // keep page and show link for testing
          setResetLink(`${process.env.REACT_APP_FRONTEND_URL || 'http://localhost:3000'}/reset-password?token=${response.data.token}`);
          setShowLink(true);
        } else {
          setSubmitted(true);
          // Redirect to login after 3 seconds
          setTimeout(() => {
            navigate('/login');
          }, 3000);
        }
      } else {
        toast.error(response.data.message || 'Failed to send reset link');
      }
    } catch (error) {
      console.error('Forgot password error:', error);
      const errorMsg = error.response?.data?.message || 'Failed to send reset link';
      toast.error(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  if (submitted) {
    return (
      <div className="container">
        <div className="auth-container">
          <h1>Check Your Email</h1>
          <div style={{
            background: '#e8f5e9',
            padding: '20px',
            borderRadius: '8px',
            textAlign: 'center',
            marginBottom: '20px'
          }}>
            <p style={{margin: 0, color: '#2e7d32', fontSize: '16px'}}>
              ✓ Password reset link has been sent to <strong>{email}</strong>
            </p>
          </div>
          <p style={{textAlign: 'center', marginBottom: '20px'}}>
            Please check your email and follow the link to reset your password.
          </p>
          <p style={{textAlign: 'center', marginBottom: '20px', fontSize: '14px', color: '#666'}}>
            Redirecting to login page in 3 seconds...
          </p>
          <Link to="/login" className="btn btn-primary btn-block">
            Back to Login
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="auth-container">
        <h1>Forgot Password?</h1>
        <p style={{textAlign: 'center', color: '#666', marginBottom: '30px'}}>
          Enter your email address and we'll send you a link to reset your password.
        </p>

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Email Address</label>
            <div style={{display: 'flex', gap: '8px', alignItems: 'flex-start'}}>
              <input
                type="email"
                className="form-control"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="Enter your email"
                required
                style={{flex: '0 0 80%'}}
              />
              <button
                type="submit"
                className="btn btn-primary"
                disabled={loading || !email}
                style={{flex: '0 0 20%', whiteSpace: 'nowrap', marginTop: 0}}
              >
                {loading ? 'Sending...' : 'Send'}
              </button>
            </div>
          </div>

          {showLink && resetLink && (
            <div style={{marginTop: 12, wordBreak: 'break-all'}}>
              <p style={{margin: 0}}>Dev reset link (click to test):</p>
              <a href={resetLink} target="_blank" rel="noreferrer" style={{color: '#ff6b35'}}>{resetLink}</a>
            </div>
          )}
        </form>

        <p className="text-center mt-2">
          Remember your password?{' '}
          <Link to="/login">Back to Login</Link>
        </p>
      </div>
    </div>
  );
};
 
export default ForgotPasswordPage;
